import React from 'react';
import './BlogPage.css';

const posts = [
  {
    slug: 'visual-identity',
    title: 'How to build a visual identity that stands out',
    date: 'Mar 20, 2025',
    img: 'https://framerusercontent.com/images/2pZn1ac5q54fkkThIF56Vfou8.jpg',
  },
  {
    slug: 'digital-world',
    title: 'How to stay relevant in a fast-changing digital world',
    date: 'Mar 13, 2025',
    img: 'https://framerusercontent.com/images/xAmaN93UEGZxWaE2SAlY2hCRj08.jpeg',
  },
  {
    slug: 'web-design-mistakes',
    title: 'Web design mistakes that kill conversions and how to fix them',
    date: 'Mar 6, 2025',
    img: 'https://framerusercontent.com/images/Ul6TqjNd7W2EUvsj95U3eWhy9HQ.jpg',
  },
  {
    slug: 'minimalism-maximalism',
    title: 'Minimalism vs. Maximalism: which design style fits your brand?',
    date: 'Feb 27, 2025',
    img: 'https://framerusercontent.com/images/XJvmH5y4Hijz10YCoqGtZqN4KWI.jpg',
  },

];

export default function BlogPage() {
  return (
    <main className="blog-page">
      {/* Header */}
      <section className="blog-page-header">
        <div className="container">
          <h1 className="blog-page-title">Blog.</h1>
          <p className="blog-page-sub">
            Our blog delivers actionable tips to help you build a powerful, timeless brand.
          </p>
        </div>
      </section>

      {/* Grid */}
      <section className="blog-content">
        <div className="blog-posts-grid">
          {posts.map(post => (
            <article key={post.slug} className="blog-post-card">
              <div className="post-img">
                <img src={post.img} alt={post.title} />
              </div>
              <div className="post-body">
                <h3 className="post-title">{post.title}</h3>
                <span className="post-date">{post.date}</span>
                <span className="read-link">Read article →</span>
              </div>
            </article>
          ))}
        </div>
      </section>
    </main>
  );
}
